import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.Lq6hU67C.js";const p=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),s={name:"guide/quick-start.md"};function l(i,e,n,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">‚Äã</a></h1><p>This guide gets you from zero to a visible <strong>Live Leaks</strong> entry in a few minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">‚Äã</a></h2><ul><li>Unity project with Addressables Leak Detector installed (see <a href="./installation.html">Installation</a>).</li><li><code>com.unity.addressables</code> and <code>com.unity.nuget.mono-cecil</code> in <code>Packages/manifest.json</code>.</li><li>You are comfortable entering <strong>Play Mode</strong> in the Editor.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">‚Äã</a></h2><h3 id="_1-open-the-window" tabindex="-1">1. Open the window <a class="header-anchor" href="#_1-open-the-window" aria-label="Permalink to &quot;1. Open the window&quot;">‚Äã</a></h3><p>Use the menu: <strong>Window ‚Üí Addressables Leak Detector</strong>.</p><h3 id="_2-enable-recording" tabindex="-1">2. Enable recording <a class="header-anchor" href="#_2-enable-recording" aria-label="Permalink to &quot;2. Enable recording&quot;">‚Äã</a></h3><p>In the toolbar, ensure <strong>Recording</strong> is on. When recording is paused, new load/release events are not appended to the log.</p><h3 id="_3-enter-play-mode" tabindex="-1">3. Enter Play Mode <a class="header-anchor" href="#_3-enter-play-mode" aria-label="Permalink to &quot;3. Enter Play Mode&quot;">‚Äã</a></h3><p>Press <strong>Play</strong> and load Addressables content in your game. The tool only captures activity while the Editor is in Play Mode (and while recording is enabled).</p><h3 id="_4-read-live-leaks" tabindex="-1">4. Read Live Leaks <a class="header-anchor" href="#_4-read-live-leaks" aria-label="Permalink to &quot;4. Read Live Leaks&quot;">‚Äã</a></h3><p>Open the <strong>Live Leaks</strong> tab. Each row represents a <strong>live</strong> Addressables handle grouped by call site and asset key. Select a row to see the leak trace (load origin file:line, operation kind, severity).</p><h3 id="_5-release-and-verify" tabindex="-1">5. Release and verify <a class="header-anchor" href="#_5-release-and-verify" aria-label="Permalink to &quot;5. Release and verify&quot;">‚Äã</a></h3><p>Call <code>Addressables.Release</code> (or the matching release API) for the handle. The entry should disappear from Live Leaks after the release is recorded.</p><h2 id="global-checklist" tabindex="-1">Global checklist <a class="header-anchor" href="#global-checklist" aria-label="Permalink to &quot;Global checklist&quot;">‚Äã</a></h2><ol><li>Package imported under <code>Assets/AddressablesLeakDetector</code>.</li><li><strong>Mono.Cecil</strong> and <strong>Addressables</strong> in <code>manifest.json</code>.</li><li><strong>Window ‚Üí Addressables Leak Detector</strong> opened; <strong>Recording</strong> on.</li><li>User scripts <strong>recompiled</strong> after import (ILPP runs at compile time).</li><li>Your game code uses instrumented Addressables APIs (see <a href="./../reference/supported-call-sites.html">Supported call sites</a>).</li></ol><p>No <code>using AddressablesLeakDetector.Runtime</code> or manual <code>HandleTracker</code> calls are required in normal user code.</p><h2 id="demo-scene-fastest-path" tabindex="-1">Demo scene (fastest path) <a class="header-anchor" href="#demo-scene-fastest-path" aria-label="Permalink to &quot;Demo scene (fastest path)&quot;">‚Äã</a></h2><ol><li><strong>Tools ‚Üí Addressables Leak Detector ‚Üí Create Demo Scene</strong></li><li>Open <code>DemoLeakScene</code> and enter Play Mode.</li><li>Click <strong>Create Leak</strong> ‚Äî expect a live handle with origin <code>LeakDemoController.cs</code>.</li><li>Click <strong>Load + Release</strong> ‚Äî expect no live handle after release.</li></ol><p>See <a href="./../how-to/demo-scene.html">Demo scene</a> for the full button matrix.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">‚Äã</a></h2><ul><li><a href="./installation.html">Installation</a></li><li><a href="./code-example.html">Minimal code example</a></li><li><a href="./../how-to/reading-live-leaks.html">Reading Live Leaks</a></li><li><a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a></li></ul>',23)])])}const m=a(s,[["render",l]]);export{p as __pageData,m as default};
